export function nextGeneration(livingCells: Set<string>): Set<string> {
  const next = new Set<string>();
  const candidates = new Set<string>();

  for (const cell of livingCells) {
    const [x, y] = cell.split(",").map(Number);
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.add(`${x + dx},${y + dy}`);
      }
    }
  }

  for (const cell of candidates) {
    const [x, y] = cell.split(",").map(Number);
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (livingCells.has(`${x + dx},${y + dy}`)) count++;
      }
    }
    const isAlive = livingCells.has(cell);
    if (isAlive && (count === 2 || count === 3)) next.add(cell);
    else if (!isAlive && count === 3) next.add(cell);
  }

  return next;
}
